@namespace Lumeo
@inject NavigationManager Nav
@implements IDisposable

@{
    var context = new MegaMenuContext(
        _activeItemId,
        EventCallback.Factory.Create<string?>(this, SetActiveItemId),
        Orientation,
        _itemIds,
        _disabledItemIds,
        _rovingItemId ?? _itemIds.FirstOrDefault(id => !_disabledItemIds.Contains(id)),
        RegisterItem,
        UnregisterItem,
        SetRovingItem);
}

<nav class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        <ul class="@ListCssClass" role="menubar" aria-orientation="@OrientationStr">
            @ChildContent
        </ul>
    </CascadingValue>
</nav>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public Lumeo.Orientation Orientation { get; set; } = Lumeo.Orientation.Horizontal;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string? _activeItemId;
    // Ordered list of registered top-level trigger ids (DOM order) backing the
    // roving-tabindex arrow navigation across the menubar (WAI-ARIA menubar).
    private readonly List<string> _itemIds = [];
    // Trigger ids registered with Disabled=true — roving arrow/Home/End nav skips
    // these so focus never lands on a non-interactive trigger.
    private readonly HashSet<string> _disabledItemIds = [];
    // The single item currently in the tab order (tabindex=0). Null until the
    // first item registers; the context falls back to the first enabled item.
    private string? _rovingItemId;

    protected override void OnInitialized()
    {
        Nav.LocationChanged += OnLocationChanged;
    }

    // A mega-menu panel is a navigation affordance: once the user follows a link
    // (or any in-app navigation happens) the open panel must close. Without this
    // it lingers over the new page in a Blazor SPA, where the menu isn't unmounted
    // on navigation the way a full page load would tear it down.
    private void OnLocationChanged(object? sender, Microsoft.AspNetCore.Components.Routing.LocationChangedEventArgs e)
    {
        if (_activeItemId is not null)
        {
            _activeItemId = null;
            InvokeAsync(StateHasChanged);
        }
    }

    public void Dispose()
    {
        Nav.LocationChanged -= OnLocationChanged;
    }

    private string CssClass => Cx.Merge("relative", Class);

    private string OrientationStr => Orientation == Lumeo.Orientation.Vertical ? "vertical" : "horizontal";

    private string ListCssClass => Orientation == Lumeo.Orientation.Vertical
        ? "flex flex-col gap-1"
        : "flex items-center gap-1";

    private Task SetActiveItemId(string? value)
    {
        _activeItemId = value;
        StateHasChanged();
        return Task.CompletedTask;
    }

    private void RegisterItem(string triggerId, bool disabled)
    {
        var shouldRender = false;

        if (!_itemIds.Contains(triggerId))
        {
            _itemIds.Add(triggerId);
            shouldRender = true;
        }

        // Track disabled state so roving nav can skip non-interactive triggers.
        // Re-render on a change even for an already-registered item so the
        // menubar tabindex stays in sync when a trigger enables/disables.
        var disabledChanged = disabled
            ? _disabledItemIds.Add(triggerId)
            : _disabledItemIds.Remove(triggerId);
        if (disabledChanged) shouldRender = true;

        // The tab stop must be an enabled trigger — a disabled one can't receive
        // focus, which would strand keyboard users at the menubar entry point.
        if (_rovingItemId is null || _disabledItemIds.Contains(_rovingItemId))
        {
            var next = _itemIds.FirstOrDefault(id => !_disabledItemIds.Contains(id));
            if (_rovingItemId != next)
            {
                _rovingItemId = next;
                shouldRender = true;
            }
        }

        if (shouldRender) StateHasChanged();
    }

    private void UnregisterItem(string triggerId)
    {
        _disabledItemIds.Remove(triggerId);
        if (_itemIds.Remove(triggerId))
        {
            if (_rovingItemId == triggerId)
            {
                _rovingItemId = _itemIds.FirstOrDefault(id => !_disabledItemIds.Contains(id));
            }
            StateHasChanged();
        }
    }

    // Roving update from an item gaining focus / arrow navigation. Kept in the
    // parent so exactly one trigger carries tabindex=0 at any time.
    private void SetRovingItem(string triggerId)
    {
        if (_rovingItemId != triggerId)
        {
            _rovingItemId = triggerId;
            StateHasChanged();
        }
    }

    public record MegaMenuContext(
        string? ActiveItemId,
        EventCallback<string?> SetActiveItemId,
        Lumeo.Orientation Orientation,
        IReadOnlyList<string> ItemIds,
        IReadOnlySet<string> DisabledItemIds,
        string? RovingItemId,
        Action<string, bool> RegisterItem,
        Action<string> UnregisterItem,
        Action<string> SetRovingItem);
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (Title is not null)
    {
        <h4 class="text-sm font-semibold text-foreground mb-3">@Title</h4>
    }
    <ul class="space-y-1" role="group">
        @ChildContent
    </ul>
</div>

@code {
    [Parameter] public string? Title { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(Class);
}

@namespace Lumeo
@using Lumeo.Services
@implements IAsyncDisposable

@{
    var itemContext = new MegaMenuItemContext(_itemId, _triggerId);
}

<CascadingValue Value="itemContext" IsFixed="false">
    @if (ChildContent is null && Href is not null)
    {
        @* keydown sits on the <li> so Arrow/Home/End roving works on the link
           variant too, matching the button variant. *@
        <li role="none" id="@_itemId" class="@CssClass" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
            <a href="@Href"
               id="@_triggerId"
               role="menuitem"
               tabindex="@RovingTabIndex"
               class="@TriggerCssClass"
               @onfocusin="HandleFocusIn">
                @if (Icon is not null)
                {
                    <Blazicon Svg="@Icon" class="h-4 w-4" />
                }
                @Label
            </a>
        </li>
    }
    else
    {
        @* keydown sits on the <li> (not the trigger button) so Escape also
           catches events bubbling from focusable elements INSIDE the open
           panel, per the overlay rules. Arrow/Home/End move roving focus
           between the top-level triggers (WAI-ARIA menubar). *@
        <li role="none"
            id="@_itemId"
            class="@CssClass"
            @onpointerenter="HandlePointerEnter"
            @onpointerleave="HandlePointerLeave"
            @onkeydown="HandleKeyDown"
            @attributes="AdditionalAttributes">
            <button id="@_triggerId"
                    type="button"
                    role="menuitem"
                    aria-haspopup="true"
                    aria-expanded="@(_isOpen ? "true" : "false")"
                    tabindex="@RovingTabIndex"
                    disabled="@Disabled"
                    class="@TriggerCssClass"
                    @onclick="HandleClick"
                    @onfocusin="HandleFocusIn">
                @if (Icon is not null)
                {
                    <Blazicon Svg="@Icon" class="h-4 w-4" />
                }
                @Label
                <Blazicon Svg="Lucide.ChevronDown" class="@ChevronCssClass" />
            </button>
            @if (_isOpen)
            {
                @ChildContent
            }
        </li>
    }
</CascadingValue>

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public MegaMenu.MegaMenuContext Context { get; set; } = default!;
    [Parameter] public string Label { get; set; } = string.Empty;
    [Parameter] public SvgIcon? Icon { get; set; }
    [Parameter] public string? Href { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = LumeoIds.New("megamenu-item");
    private readonly string _triggerId = LumeoIds.New("megamenu-trigger");
    private readonly DelayedDispatch _dispatch = new();
    private const int CloseDelay = 150;

    private bool _clickOutsideRegistered;
    private string? _clickOutsideId;
    private bool _registeredItem;

    private bool _isOpen => Context?.ActiveItemId == _itemId;

    // Roving tabindex: exactly one top-level trigger is in the tab order
    // (tabindex=0); the rest are -1 so Tab enters/leaves the menubar once and
    // Arrow keys move within it (WAI-ARIA menubar). Falls back to tabbable when
    // no roving item has been resolved yet (single-item / pre-registration).
    private string RovingTabIndex =>
        (Context?.RovingItemId is null || Context.RovingItemId == _triggerId) ? "0" : "-1";

    private string CssClass => Class ?? "";

    private string TriggerCssClass => Cx.Join(
        "inline-flex items-center gap-1.5 px-3 py-2 text-sm font-medium text-foreground hover:bg-accent hover:text-accent-foreground rounded-md transition-colors focus:outline-none focus:bg-accent focus:text-accent-foreground disabled:pointer-events-none disabled:opacity-50",
        Cx.When(_isOpen, "bg-accent/50"));

    private string ChevronCssClass => Cx.Join(
        "h-3 w-3 transition-transform duration-200",
        Cx.When(_isOpen, "rotate-180"));

    protected override void OnInitialized()
    {
        // Register in DOM order so the parent can resolve arrow-key neighbours
        // and assign the roving tab stop.
        Context?.RegisterItem(_triggerId, Disabled);
        _registeredItem = true;
    }

    // Re-report the current Disabled state on every parameter change so a
    // late toggle (Disabled flipped after first render) updates the parent
    // registry instead of leaving the stale value captured in OnInitialized.
    // RegisterItem upserts — it refreshes _disabledItemIds and re-renders only
    // when the flag actually changed — so re-reporting each time is cheap.
    protected override void OnParametersSet()
    {
        if (_registeredItem) Context?.RegisterItem(_triggerId, Disabled);
    }

    // Overlay rules: dismiss the open panel when the user clicks/taps outside
    // the item. The <li> (_itemId) contains both the trigger and the panel, so
    // inside-clicks never fire the handler; the trigger id is excluded as well
    // so a trigger click only runs its own toggle instead of racing the
    // outside-dismiss handler.
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_isOpen && !_clickOutsideRegistered)
        {
            // Register against the rendered id — a consumer `id` in the splat
            // overrides _itemId on the <li>, so getElementById(_itemId) would
            // return null and the panel would never close on outside click
            // (Codex P2). _itemId stays the logical key for ActiveItemId.
            _clickOutsideId = LumeoIds.Effective(AdditionalAttributes, _itemId);
            await Interop.RegisterClickOutside(_clickOutsideId, _triggerId, async () =>
            {
                if (Context.ActiveItemId == _itemId)
                {
                    await Context.SetActiveItemId.InvokeAsync(null);
                }
                await InvokeAsync(StateHasChanged);
            });
            _clickOutsideRegistered = true;
        }
        else if (!_isOpen && _clickOutsideRegistered)
        {
            await CleanupClickOutside();
        }
    }

    // rc.44 — Approach B: pointer events gated to mouse only. Touch devices
    // open via @onclick on the inner trigger button, avoiding the
    // tap-emulated-mouseenter / lift-emulated-mouseleave race that would
    // close the submenu before the user could pick a sub-item.
    private void HandlePointerEnter(PointerEventArgs e)
    {
        if (e.PointerType != "mouse") return;
        _dispatch.Cancel();

        if (!_isOpen)
        {
            SafeAsyncDispatcher.FireAndForget(InvokeAsync, async () =>
            {
                await Context.SetActiveItemId.InvokeAsync(_itemId);
                StateHasChanged();
            }, "MegaMenuItem.HandlePointerEnter");
        }
    }

    private void HandlePointerLeave(PointerEventArgs e)
    {
        if (e.PointerType != "mouse") return;
        if (_isOpen)
        {
            _dispatch.Schedule(CloseDelay, () =>
            {
                SafeAsyncDispatcher.FireAndForget(InvokeAsync, async () =>
                {
                    if (Context.ActiveItemId == _itemId)
                    {
                        await Context.SetActiveItemId.InvokeAsync(null);
                        StateHasChanged();
                    }
                }, "MegaMenuItem.HandlePointerLeave");
            });
        }
    }

    private async Task HandleClick()
    {
        if (_isOpen)
        {
            await Context.SetActiveItemId.InvokeAsync(null);
        }
        else
        {
            await Context.SetActiveItemId.InvokeAsync(_itemId);
        }
    }

    // Keep the roving tab stop on whichever trigger the user focuses (mouse or
    // Tab), so re-entering the menubar with Tab lands on the last-focused item.
    private void HandleFocusIn()
    {
        Context?.SetRovingItem(_triggerId);
    }

    // Enter and Space are deliberately NOT handled here: the trigger is a
    // native <button>, so the browser synthesizes a click for them and
    // HandleClick performs the toggle. Toggling from keydown as well made
    // keyboard activation a net no-op (keydown opened, the synthesized click
    // immediately toggled the panel closed again).
    //
    // Arrow/Home/End implement the WAI-ARIA menubar roving navigation between
    // the top-level triggers. The orientation picks which arrow pair moves
    // focus (horizontal: Left/Right; vertical: Up/Down). Escape closes an open
    // panel.
    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await Context.SetActiveItemId.InvokeAsync(null);
                break;
            case "ArrowRight" when Context.Orientation == Lumeo.Orientation.Horizontal:
            case "ArrowDown" when Context.Orientation == Lumeo.Orientation.Vertical:
                await MoveFocus(1);
                break;
            case "ArrowLeft" when Context.Orientation == Lumeo.Orientation.Horizontal:
            case "ArrowUp" when Context.Orientation == Lumeo.Orientation.Vertical:
                await MoveFocus(-1);
                break;
            case "Home":
                await FocusEdge(first: true);
                break;
            case "End":
                await FocusEdge(first: false);
                break;
        }
    }

    private async Task MoveFocus(int delta)
    {
        // Skip disabled triggers so arrow nav never lands on a non-interactive item.
        var ids = Context.ItemIds.Where(id => !Context.DisabledItemIds.Contains(id)).ToList();
        if (ids.Count == 0) return;
        var current = ids.IndexOf(_triggerId);
        if (current < 0) return;
        var next = (current + delta + ids.Count) % ids.Count;
        await FocusTrigger(ids[next]);
    }

    private async Task FocusEdge(bool first)
    {
        var ids = Context.ItemIds.Where(id => !Context.DisabledItemIds.Contains(id)).ToList();
        if (ids.Count == 0) return;
        await FocusTrigger(first ? ids[0] : ids[^1]);
    }

    private async Task FocusTrigger(string triggerId)
    {
        // Move the roving tab stop first so the target renders tabindex=0, then
        // focus it via interop. SetRovingItem triggers a parent re-render.
        Context.SetRovingItem(triggerId);
        try { await Interop.FocusElement(triggerId); } catch (JSDisconnectedException) { }
    }

    private async Task CleanupClickOutside()
    {
        try { await Interop.UnregisterClickOutside(_clickOutsideId ?? _itemId); } catch (JSDisconnectedException) { }
        _clickOutsideRegistered = false;
    }

    public async ValueTask DisposeAsync()
    {
        _dispatch.Dispose();
        if (_registeredItem) Context?.UnregisterItem(_triggerId);
        if (_clickOutsideRegistered) await CleanupClickOutside();
    }

    public record MegaMenuItemContext(string ItemId, string TriggerId);
}

@namespace Lumeo

<li @attributes="AdditionalAttributes">
    <a href="@Href" class="@CssClass" aria-disabled="@(Disabled ? "true" : null)">
        @if (Icon is not null)
        {
            <Blazicon Svg="@Icon" class="h-5 w-5 mt-0.5 text-muted-foreground shrink-0" />
        }
        <div>
            <div class="text-sm font-medium text-foreground">@Title</div>
            @if (Description is not null)
            {
                <p class="text-xs text-muted-foreground mt-0.5">@Description</p>
            }
        </div>
    </a>
</li>

@code {
    [Parameter] public string Href { get; set; } = "#";
    [Parameter] public string Title { get; set; } = string.Empty;
    [Parameter] public string? Description { get; set; }
    [Parameter] public SvgIcon? Icon { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(
        "flex items-start gap-3 rounded-md p-2 hover:bg-accent transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1",
        Cx.When(Disabled, "pointer-events-none opacity-50"),
        Class);
}

@namespace Lumeo

<div class="@CssClass" role="menu" @attributes="AdditionalAttributes">
    <div class="@GridCssClass">
        @ChildContent
    </div>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool FullWidth { get; set; } = true;
    [Parameter] public int Columns { get; set; } = 4;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string WidthCssClass => FullWidth ? "start-0 end-0" : "w-auto min-w-[600px]";

    private string CssClass => Cx.Merge("absolute top-full z-50", WidthCssClass, "bg-popover border border-border/40 rounded-lg shadow-lg p-6", Class);

    private string GridCssClass => Columns switch {
        1 => "grid grid-cols-1 gap-6",
        2 => "grid grid-cols-2 gap-6",
        3 => "grid grid-cols-3 gap-6",
        4 => "grid grid-cols-4 gap-6",
        5 => "grid grid-cols-5 gap-6",
        _ => "grid grid-cols-1 gap-6"
    };
}
